<template>
    <div class="page">
        <div class="search between">
            <div></div>
            <el-button type="primary" @click="toPath('/notice/detail', null, '1')">新增</el-button>
        </div>
        <el-table :data="tableData" border style="width: 100%" v-loading="loading">
            <el-table-column label="序号" type="index" width="50"></el-table-column>

            <el-table-column label="用户头像" width="120"  header-align="center" align="center">
                <template slot-scope="scope">
                    <img :src="scope.row.avatarUrl || ''" alt="" style="width: 80px; height: 80px; border-radius: 50%; margin: auto">
                </template>
            </el-table-column>
            
            <el-table-column v-for="(item, index) in column" :key="index"  header-align="center"  align="center"
                :prop="item.prop" :label="item.label" :width="item.width">
            </el-table-column>
            
            <el-table-column fixed="right" label="操作" width="200"  header-align="center" align="center">
                <template slot-scope="scope">
                    <el-button type="text" size="small" @click="contactUser(scope.row.id)">联系用户</el-button>
                </template>
            </el-table-column>
        </el-table>
    </div>
</template>
  
<script>
import {queryUserList, deleteNotice} from "@/http/api"
export default {
    data(){
        return {
            column: [
                { label: "用户昵称", prop: "nickName", width: "200" },
                { label: "真实姓名", prop: "realname", width: "120" },
                { label: "联系电话", prop: "phone", width: "" },
                { label: "第二联系电话", prop: "twophone", width: "" },
            ],
            tableData: [],
            
            pageNumber: 1,
            pageSize: 10,
            total: 0
        }
    },
    created(){
        this.queryUserList()
    },
    methods: {
        async deleteItem(id){
            this.loading = true
            const res = await deleteNotice({id})
            const {code, data, msg} = res
            if(code === 0){
                this.$message.success("操作成功")
                this.queryUserList()
            }else{
                this.$message.error(msg)
            }
            this.loading = false
        },
        async queryUserList(){
            this.loading = true
            const params = {
                pageNumber: this.pageNumber,
                pageSize: this.pageSize,
            }
            const res = await queryUserList(params)
            const {code, data, msg} = res
            if(code === 0){
                this.tableData = data.list.map((item, index)=>{
                    return {
                        ...item,
                        index: index + 1
                    }
                })
            }else{
                this.$message.error(msg)
            }
            this.loading = false
        },
        handleClick(row){
            console.log('row', row)
        },
        toPath(path, id, type){
            this.$router.push({
                path,
                query:{id, type}
            })
        }
    }
}
</script>
  
<style lang="scss" scoped>
    .search{
        margin: 30px 0;
    }
</style>
  